mapper.select:
SELECT id, service_name, job_code, job_name, cron_expr, run_mode, enabled, timeout_ms, remark, params_json, create_by, create_time, update_by, update_time FROM job_def
deleted = 0
AND service_name LIKE CONCAT('%', #{dto.serviceName}, '%')
AND job_code LIKE CONCAT('%', #{dto.jobCode}, '%')
AND job_name LIKE CONCAT('%', #{dto.jobName}, '%')
AND enabled = #{dto.enabled}
AND create_time >= #{dto.createTimeStart}
AND create_time <= #{dto.createTimeEnd}
ORDER BY create_time DESC, id DESC
